//! Deterministic Phase 1 Criterion benchmarks.
//!
//! Run with:
//! ```text
//! cargo bench -p scirust-hypermemory
//! ```
//!
//! Corpora are generated by a fixed-seed in-crate LCG (no RNG dependency), so a
//! run is reproducible. **No numbers are committed as fact** — see
//! `docs/research/SCIRUST_HYPERMEMORY_PHASE1.md` §11. If you report timings,
//! report the exact hardware, compiler version, `cargo` invocation, and commit.
//!
//! Measured: concept insertion, exact lookup by id, exhaustive top-k search at
//! several corpus sizes, expression evaluation at several depths, a single
//! sedenion product, the real-16 baseline search, and (for comparison) the
//! independent `scirust_retrieval::DenseIndex` search.

// Bench-schema migration (scirust-bench-schema): every corpus here comes
// from the in-file `Lcg`, seeded via `Lcg::new(seed)` (which XORs the given
// seed with 0x9E37_79B9_7F4A_7C15) and driven through `anchors(n, seed)`.
// Per function: bench_insertion uses anchors(1_000, 0xA1); bench_lookup_by_id
// uses anchors(10_000, 0xB2); bench_search / bench_real16_search /
// bench_dense_index_search each use anchors(n, 0xC3 ^ n as u64) for n in
// SIZES; bench_expression_evaluation uses anchors(8, 0xD4); and
// bench_sedenion_product seeds Lcg::new(0xE5) directly.
//
// Example conversion, for the "exact_topk_search_cosine" group's n=10_000
// case (target/criterion/exact_topk_search_cosine/10000/new/estimates.json):
//
//   scirust_bench_schema::criterion_estimate_to_record(
//       &estimates_json,
//       "scirust-hypermemory/exact_topk_search",
//       "corpus_n=10000",
//       "S16ExactIndex::search(cosine)",
//       0xC3 ^ 10_000u64, // = 10_195
//   )?;
//
// See scirust-bench-schema's crate docs ("Migrating criterion targets") for
// the full pattern.

use criterion::{BenchmarkId, Criterion, black_box, criterion_group, criterion_main};
use scirust_hypermemory::{
    ConceptId, ConceptSpec, ExprLimits, Real16Index, S16ExactIndex, S16Expr, S16Store,
    SimilarityMetric,
};
use scirust_retrieval::DenseIndex;
use scirust_simd::hypercomplex::SedenionSimd;

/// The corpus sizes swept by the search benchmarks.
const SIZES: [usize; 3] = [1_000, 10_000, 100_000];

/// Fixed-seed LCG — deterministic corpus generation, no external RNG dependency.
struct Lcg(u64);

impl Lcg {
    fn new(seed: u64) -> Self {
        Self(seed ^ 0x9E37_79B9_7F4A_7C15)
    }

    fn next_u64(&mut self) -> u64 {
        self.0 = self
            .0
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        self.0
    }

    fn next_f32(&mut self) -> f32 {
        let bits = (self.next_u64() >> 40) as u32;
        (bits as f32 / (1u32 << 24) as f32) * 2.0 - 1.0
    }

    fn nonzero_sedenion(&mut self) -> SedenionSimd {
        loop
        {
            let mut a = [0.0f32; 16];
            for lane in &mut a
            {
                *lane = self.next_f32();
            }
            let s = SedenionSimd::from_array(a);
            if s.to_array().iter().any(|x| *x != 0.0)
            {
                return s;
            }
        }
    }
}

/// Deterministic anchors for a corpus of `n` concepts.
fn anchors(n: usize, seed: u64) -> Vec<SedenionSimd> {
    let mut rng = Lcg::new(seed);
    (0..n).map(|_| rng.nonzero_sedenion()).collect()
}

/// Build a populated store from pre-generated anchors.
fn populated_store(anchors: &[SedenionSimd]) -> (S16Store, Vec<ConceptId>) {
    let mut store = S16Store::new();
    let mut ids = Vec::with_capacity(anchors.len());
    for (i, &anchor) in anchors.iter().enumerate()
    {
        ids.push(
            store
                .insert(ConceptSpec::new(vec![i as u8], anchor, 1.0, 0))
                .unwrap(),
        );
    }
    (store, ids)
}

fn bench_insertion(c: &mut Criterion) {
    let corpus = anchors(1_000, 0xA1);
    c.bench_function("insert_1000_concepts", |b| {
        b.iter(|| {
            let mut store = S16Store::new();
            for (i, &anchor) in corpus.iter().enumerate()
            {
                let id = store
                    .insert(ConceptSpec::new(vec![i as u8], anchor, 1.0, 0))
                    .unwrap();
                black_box(id);
            }
            black_box(store.len())
        })
    });
}

fn bench_lookup_by_id(c: &mut Criterion) {
    let corpus = anchors(10_000, 0xB2);
    let (store, ids) = populated_store(&corpus);
    let target = ids[ids.len() / 2];
    c.bench_function("lookup_by_id_10000", |b| {
        b.iter(|| black_box(store.get(black_box(target)).unwrap().sequence()))
    });
}

fn bench_search(c: &mut Criterion) {
    let mut group = c.benchmark_group("exact_topk_search_cosine");
    for &n in &SIZES
    {
        let corpus = anchors(n, 0xC3 ^ n as u64);
        let (store, _ids) = populated_store(&corpus);
        let mut index = S16ExactIndex::new(SimilarityMetric::Cosine);
        index.rebuild_from(store.iter());
        let query = SedenionSimd::unit(3) + SedenionSimd::unit(9);
        group.bench_with_input(BenchmarkId::from_parameter(n), &n, |b, _| {
            b.iter(|| black_box(index.search(black_box(&query), 10).unwrap()))
        });
    }
    group.finish();
}

fn bench_real16_search(c: &mut Criterion) {
    let mut group = c.benchmark_group("real16_topk_search_cosine");
    for &n in &SIZES
    {
        let corpus = anchors(n, 0xC3 ^ n as u64);
        let (store, _ids) = populated_store(&corpus);
        let mut index = Real16Index::new(SimilarityMetric::Cosine);
        index.rebuild_from(store.iter());
        let query = SedenionSimd::unit(3) + SedenionSimd::unit(9);
        group.bench_with_input(BenchmarkId::from_parameter(n), &n, |b, _| {
            b.iter(|| black_box(index.search(black_box(&query), 10).unwrap()))
        });
    }
    group.finish();
}

fn bench_dense_index_search(c: &mut Criterion) {
    let mut group = c.benchmark_group("dense_index_topk_search_cosine");
    for &n in &SIZES
    {
        let corpus = anchors(n, 0xC3 ^ n as u64);
        let (store, _ids) = populated_store(&corpus);
        let mut dense = DenseIndex::new(16);
        for record in store.iter()
        {
            dense
                .add(record.sequence(), &record.effective().to_array())
                .unwrap();
        }
        let query = (SedenionSimd::unit(3) + SedenionSimd::unit(9)).to_array();
        group.bench_with_input(BenchmarkId::from_parameter(n), &n, |b, _| {
            b.iter(|| black_box(dense.search(black_box(&query), 10)))
        });
    }
    group.finish();
}

fn bench_expression_evaluation(c: &mut Criterion) {
    // A left-leaning chain of the requested depth over a small atom pool.
    let corpus = anchors(8, 0xD4);
    let (store, ids) = populated_store(&corpus);
    let limits = ExprLimits::new(4096, 1 << 20).unwrap();

    let mut group = c.benchmark_group("expression_evaluation");
    for &depth in &[2usize, 8, 32, 128]
    {
        let mut expr = S16Expr::atom(ids[0]);
        for i in 1..depth
        {
            expr = S16Expr::product(expr, S16Expr::atom(ids[i % ids.len()]));
        }
        group.bench_with_input(BenchmarkId::from_parameter(depth), &depth, |b, _| {
            b.iter(|| black_box(expr.evaluate(&store, &limits).unwrap()))
        });
    }
    group.finish();
}

fn bench_sedenion_product(c: &mut Criterion) {
    let mut rng = Lcg::new(0xE5);
    let x = rng.nonzero_sedenion();
    let y = rng.nonzero_sedenion();
    c.bench_function("sedenion_product", |b| {
        b.iter(|| black_box(black_box(x) * black_box(y)))
    });
}

criterion_group!(
    benches,
    bench_insertion,
    bench_lookup_by_id,
    bench_search,
    bench_real16_search,
    bench_dense_index_search,
    bench_expression_evaluation,
    bench_sedenion_product,
);
criterion_main!(benches);
